  }

  OPTIONAL {
    ?country p:P2148 ?femaleStmt .
    ?femaleStmt ps:P2148 ?femaleRate_val ;
                pq:P21 wd:Q6571072 .
    BIND(xsd:double(?femaleRate_val) AS ?femaleSuicideRate)
