  }
}

SELECT ?country ?countryLabel ?hdi (xsd:double(?popGrowth) AS ?popGrowthRate) (xsd:double(?maleRate) AS ?maleSuicideRate) (xsd:double(?femaleRate) AS ?femaleSuicideRate) WHERE {

  { 
    SELECT ?country (xsd:double(?hdi_val) AS ?hdi) WHERE {
      ?country wdt:P31 wd:Q6256 .
      ?country wdt:P1081 ?hdi_val .
      FILTER(xsd:double(?hdi_val) > 0)
    }
    ORDER BY DESC(?hdi_val)
    LIMIT 10
  }

  ?country rdfs:label ?countryLabel FILTER(LANG(?countryLabel) = "en") .

  OPTIONAL { 
    ?country wdt:P2798 ?popGrowth .
  }

  OPTIONAL { 
    ?country p:P2148 ?suicideStmt .
    ?suicideStmt ps:P2148 ?rate ;
                   pq:P21 wd:Q6581072 .
    BIND(REPLACE(STR(?rate), "[^0-9.]+", "") AS ?cleanMaleRate)
    BIND(xsd:double(?cleanMaleRate) AS ?maleRate)
  }

  OPTIONAL { 
    ?country p:P2148 ?suicideStmtFemale .
    ?suicideStmtFemale ps:P2148 ?rateFemale ;
                      pq:P21 wd:Q6571072 .
    BIND(REPLACE(STR(?rateFemale), "[^0-9.]+", "") AS ?cleanFemaleRate)
    BIND(xsd:double(?cleanFemaleRate) AS ?femaleRate)
  }
}

